Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that speaks to it without opening a real port.

**Key pieces:**

1. **`WebApplicationFactory`** — boots your app in a test host
2. **`HttpClient`** from the factory — sends real HTTP requests in-process
3. **Send actual MCP JSON-RPC messages** over that client

Here's a minimal example:

```csharp
// MyMcpServer.IntegrationTests/McpProtocolTests.cs

using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpProtocolTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpProtocolTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("serverInfo", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsAvailableTools()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list",
            @params = new { }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 3,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result").GetProperty("content");
        Assert.True(content.GetArrayLength() > 0);
    }
}
```

**Tips:**

- Adjust `"/mcp"` to match your actual endpoint path
- Make `Program` accessible by adding `public partial class Program { }` to your server's `Program.cs`, or use `[assembly: InternalsVisibleTo("YourTestProject")]`
- Override services (e.g., swap a real DB for an in-memory one) via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))`
- If your server uses **SSE** (Streamable HTTP), read the response stream incrementally with `ReadAsStreamAsync()` and parse `text/event-stream` lines
- Add `Microsoft.AspNetCore.Mvc.Testing` NuGet to your test project

This gives you **full HTTP-level fidelity** — middleware, routing, serialization, content negotiation — all running in-process with zero network overhead.
